437	function triggerStoreSearchAPI(tableApiUrl) {
438	
439	    const uiPageSize = parseInt($jq("#pagination-per-page-886179417").val());
440	        if (uiPageSize && !isNaN(uiPageSize)) {
441	            pageSize = uiPageSize;
442	        }
443	
444	    $jq(".dds__no-resultsText").text("No results found for $srchText - please change your search criteria $srchAudText");
445	    $jq(".dds__api-error").addClass("dds__d-none");
446	    $jq(".dds__srch-data-loading").removeClass("dds__d-none");
447	    $jq(".dds__srch-data-container").addClass("dds__d-none");
448	
449	    const priceMinInput = document.getElementById("dds__price-min");
450	    const priceMaxInput = document.getElementById("dds__price-max");
451	
452	    const queryString = window.location.search.substring(1);
453	    const paramsArray = queryString.split("%26");
454	    const params = new URLSearchParams(paramsArray.join("&"));
455	
456	    window.urlParams = {
457	        categories: params.get("c") ? params.get("c").split(",").map(item => DOMPurify.sanitize(item, { ALLOWED_TAGS: [], ALLOWED_ATTR: [] })) : [],
458	        types: params.get("t") ? params.get("t").split(",").map(item => DOMPurify.sanitize(item, { ALLOWED_TAGS: [], ALLOWED_ATTR: [] })) : [],
459	        price: DOMPurify.sanitize(params.get("p"), { ALLOWED_TAGS: [], ALLOWED_ATTR: [] }),
460	        searchText: params.get("x") ? DOMPurify.sanitize(decodeURIComponent(params.get("x")), { ALLOWED_TAGS: [], ALLOWED_ATTR: [] }) : ""
461	    };
462	
463	    if (searchInput && window.urlParams.searchText) {
464	        searchInput.value = DOMPurify.sanitize(window.urlParams.searchText, { ALLOWED_TAGS: [], ALLOWED_ATTR: [] });
465	        addFilterTag(searchInput, "searchBy");
466	        $jq("#dds__srch-inputWrapper .dds__icon--close-cir").removeClass("dds__d-none");
467	    } else {
468	        $jq("#dds__srch-inputWrapper .dds__icon--close-cir").addClass("dds__d-none");
469	    }
470	
471	    if (window.urlParams.price) {
472	        const [minPrice, maxPrice] = window.urlParams.price === "FREE" ? ["0", "0"] : window.urlParams.price.split(" - ");
473	        if (priceMinInput) priceMinInput.value = String(minPrice).trim();
474	        if (priceMaxInput) priceMaxInput.value = String(maxPrice).trim();
475	        addFilterTag("", "priceRange");
476	    }
477	
478	    const firstResult = (coveocurrentPage - 1) * pageSize;
479	
480	    var usrLoc = $jq(".dt-emc-header").data("location") ? $jq(".dt-emc-header").data("location") : "United States";
481	
482	    if ($jq(".dt-emc-header").data("audtype").toUpperCase() == "GUEST" || $jq(".dt-emc-header").data("audtype").toUpperCase() == "INTERNAL") {
483	        var locCookie = readCookie("location");
484	        usrLoc = locCookie ? locCookie : "United States";
485	    }
486	
487	    let cq = `((@epaudiencetypes=="All" AND @eppriceListCode=="mpl" AND @epprice==0.0) OR (@epaudiencetypes=="${usrLoc}" AND @epcountry=="${usrLoc}")) AND (@epprice>=0 AND @epprice<99999999)`;
488	
489	    if (window.urlParams.price) {
490	        const [minPrice, maxPrice] = window.urlParams.price === "FREE" ? ["0", "0"] : window.urlParams.price.split(" - ");
491	        cq = cq.replace("(@epprice>=0 AND @epprice<99999999)", `(@epprice>=${minPrice.trim()} AND @epprice<=${maxPrice.trim()}) AND (@epprice>=0 AND @epprice<99999999)`);
492	    }
493	
494	    if (window.urlParams.categories.length > 0) {
495	        const categoriesCQ = window.urlParams.categories.map(cat => `@epcategory==\"${cat}\"`).join(" AND ");
496	        cq += ` AND (${categoriesCQ})`;
497	    }
498	
499	    const certValue = getCertSwitchValue();
500	    if (certValue) {
501	        cq += ` AND (@epcustom2==\"${certValue}\")`;
502	    }
503	
504	    if (window.urlParams.types.length > 0) {
505	        const typesCQ = window.urlParams.types.map(type => `@epmodalitycourse==\"${type}\"`).join(" AND ");
506	        cq += ` AND (${typesCQ})`;
507	    }
508	
509	    var jsonObj = {
510	        "q": searchInput ? searchInput.value.trim() : "",
511	        "searchHub": "EducationHub",
512	        "sortCriteria": "relevancy",
513	        "sortField": "fielddescedning",
514	        "enableRankingInformation": true,
515	        "firstResult": firstResult,
516	        "numberOfResults": pageSize,
517	        "cq": cq,
518	        "facets": [
519	            {
520	                "facetId": "Category",
521	                "field": "epcategory",
522	                "type": "hierarchical",
523	                "sortCriteria": "alphanumeric",
524	                "injectionDepth": 1000,
525	                "delimitingCharacter": "|",
526	                "filterFacetCount": true,
527	                "basePath": [],
528	                "filterByBasePath": false,
529	                "currentValues": [],
530	                "preventAutoSelect": false,
531	                "numberOfValues": 100,
532	                "isFieldExpanded": false
533	            },
534	            {
535	                "facetId": "Modality",
536	                "field": "epmodalitycourse",
537	                "type": "hierarchical",
538	                "sortCriteria": "nosort",
539	                "injectionDepth": 1000,
540	                "delimitingCharacter": "|",
541	                "filterFacetCount": true,
542	                "basePath": [],
543	                "filterByBasePath": false,
544	                "currentValues": [],
545	                "preventAutoSelect": false,
546	                "numberOfValues": 100,
547	                "isFieldExpanded": false
548	            }
549	        ]
550	    };
551	
552	    $jq.ajax({
553	        url: tableApiUrl,
554	        type: "POST",
555	        data: JSON.stringify(jsonObj),
556	        dataType: "json",
557	        cache: false,
558	        success: function (respObj) {
559	            processResponseObj(respObj);
560	        },
561	        error: function (errmsg) {
562	            console.log("error" + errmsg.d);
563	            setTimeout(function () {
564	                $jq(".dds__srch-data-loading").addClass("dds__d-none");
565	                $jq(".dds__srch-data-container").addClass("dds__d-none");
566	                $jq(".dds__api-error").removeClass("dds__d-none");
567	            }, 1000);
568	        }
569	    });
570	}
