572	function fetchAutocomplete(searchText) {
573	    const context = encodeURIComponent(JSON.stringify({
574	        "lang": "English",
575	        "geo": "United States"
576	    }));
577	
578	    const autoCompleteUrl = '/eduservice/cash.json/coveoautocomplete' +
579	        '?organizationId=dellsandbox2' +
580	        '&searchHub=EducationHub' +
581	        '&enableWordCompletion=false' +
582	        '&count=5' +
583	        '&context=' + context +
584	        '&limit=5' +
585	        '&q=' + encodeURIComponent(searchText);
586	
587	    $jq.ajax({
588	        url: autoCompleteUrl,
589	        type: "GET",
590	        dataType: "json",
591	        cache: false,
592	        success: function(response) {
593	            if (response && response.completions && response.completions.length > 0) {
594	                showAutocompleteList(response.completions);
595	            } else {
596	                hideAutocompleteList();
597	            }
598	        },
599	        error: function(errmsg) {
600	            console.log("Autocomplete error:", errmsg);
601	            hideAutocompleteList();
602	        }
603	    });
604	}
